'use client';
import React from 'react';
import {
  Container,
  Box,
  Typography,
  Grid,
  Card,
  CardContent,
  List,
  ListItem,
  ListItemIcon,
  ListItemText,
  Button,
} from '@mui/material';
import {
  Build,
  Engineering,
  Assignment,
  Assessment,
  CheckCircle,
  ArrowForward,
} from '@mui/icons-material';
import { motion } from 'framer-motion';
import { useRouter } from 'next/navigation';

const Services = () => {
  const router = useRouter();

  const services = [
    {
      id: 'installation',
      title: 'Solar Installation',
      icon: <Build sx={{ fontSize: 60 }} />,
      description: 'Professional installation services with certified technicians',
      features: [
        'Site assessment and design',
        'Quality equipment installation',
        'Grid connection assistance',
        'System testing and commissioning',
        'User training and documentation',
      ],
    },
    {
      id: 'maintenance',
      title: 'Maintenance & AMC',
      icon: <Engineering sx={{ fontSize: 60 }} />,
      description: 'Annual Maintenance Contracts and regular servicing',
      features: [
        'Regular system inspections',
        'Panel cleaning and maintenance',
        'Performance monitoring',
        'Fault detection and repair',
        '24/7 emergency support',
      ],
    },
    {
      id: 'subsidy',
      title: 'Government Subsidy Assistance',
      icon: <Assignment sx={{ fontSize: 60 }} />,
      description: 'Help with subsidy applications and documentation',
      features: [
        'Subsidy eligibility check',
        'Documentation support',
        'Application filing',
        'Follow-up and tracking',
        'Up to 40% subsidy available',
      ],
    },
    {
      id: 'survey',
      title: 'Site Survey & Proposal',
      icon: <Assessment sx={{ fontSize: 60 }} />,
      description: 'Comprehensive site assessment and detailed proposals',
      features: [
        'Detailed site analysis',
        'Shadow analysis',
        'ROI calculations',
        'Custom system design',
        'Financial projections',
      ],
    },
  ];

  const processSteps = [
    {
      step: 1,
      title: 'Initial Consultation',
      description: 'We understand your energy needs and requirements',
    },
    {
      step: 2,
      title: 'Site Survey',
      description: 'Comprehensive assessment of your property',
    },
    {
      step: 3,
      title: 'Custom Proposal',
      description: 'Detailed proposal with system design and pricing',
    },
    {
      step: 4,
      title: 'Installation',
      description: 'Professional installation by certified technicians',
    },
    {
      step: 5,
      title: 'Commissioning',
      description: 'System testing and handover with training',
    },
    {
      step: 6,
      title: 'Support',
      description: 'Ongoing maintenance and support services',
    },
  ];

  return (
    <Box sx={{ pt: { xs: 8, md: 10 }, pb: 8 }}>
      {/* Hero Section */}
      <Box
        sx={{
          bgcolor: 'primary.main',
          color: 'white',
          py: 8,
          textAlign: 'center',
        }}
      >
        <Container maxWidth="md">
          <motion.div
            initial={{ opacity: 0, y: 30 }}
            animate={{ opacity: 1, y: 0 }}
            transition={{ duration: 0.6 }}
          >
            <Typography variant="h1" sx={{ fontWeight: 800, mb: 3 }}>
              Our Services
            </Typography>
            <Typography variant="h5" sx={{ opacity: 0.9 }}>
              End-to-end solar solutions from consultation to maintenance
            </Typography>
          </motion.div>
        </Container>
      </Box>

      <Container maxWidth="xl" sx={{ mt: 8 }}>
        {/* Services Grid */}
        <Box sx={{ mb: 8 }}>
          <Typography
            variant="h2"
            sx={{
              textAlign: 'center',
              fontWeight: 800,
              mb: 6,
            }}
          >
            Service Offerings
          </Typography>
          <Grid container spacing={4}>
            {services.map((service, index) => (
              <Grid item xs={12} md={6} key={service.id}>
                <motion.div
                  initial={{ opacity: 0, y: 30 }}
                  whileInView={{ opacity: 1, y: 0 }}
                  viewport={{ once: true }}
                  transition={{ duration: 0.5, delay: index * 0.1 }}
                >
                  <Card sx={{ height: '100%', p: 4 }}>
                    <Box sx={{ textAlign: 'center', mb: 3, color: 'primary.main' }}>
                      {service.icon}
                    </Box>
                    <Typography variant="h4" sx={{ fontWeight: 700, mb: 2, textAlign: 'center' }}>
                      {service.title}
                    </Typography>
                    <Typography
                      variant="body1"
                      color="text.secondary"
                      sx={{ mb: 3, textAlign: 'center' }}
                    >
                      {service.description}
                    </Typography>
                    <List>
                      {service.features.map((feature, idx) => (
                        <ListItem key={idx} disablePadding sx={{ mb: 1 }}>
                          <ListItemIcon sx={{ minWidth: 36 }}>
                            <CheckCircle sx={{ color: 'secondary.main', fontSize: 20 }} />
                          </ListItemIcon>
                          <ListItemText primary={feature} />
                        </ListItem>
                      ))}
                    </List>
                    <Button
                      variant="contained"
                      fullWidth
                      endIcon={<ArrowForward />}
                      onClick={() => router.push('/contact')}
                      sx={{ mt: 3 }}
                    >
                      Learn More
                    </Button>
                  </Card>
                </motion.div>
              </Grid>
            ))}
          </Grid>
        </Box>

        {/* Process Steps */}
        <Box>
          <Typography
            variant="h2"
            sx={{
              textAlign: 'center',
              fontWeight: 800,
              mb: 6,
            }}
          >
            Our Process
          </Typography>
          <Grid container spacing={4}>
            {processSteps.map((step, index) => (
              <Grid item xs={12} sm={6} md={4} key={index}>
                <motion.div
                  initial={{ opacity: 0, y: 30 }}
                  whileInView={{ opacity: 1, y: 0 }}
                  viewport={{ once: true }}
                  transition={{ duration: 0.5, delay: index * 0.1 }}
                >
                  <Card
                    sx={{
                      height: '100%',
                      p: 3,
                      textAlign: 'center',
                      position: 'relative',
                    }}
                  >
                    <Box
                      sx={{
                        width: 60,
                        height: 60,
                        borderRadius: '50%',
                        bgcolor: 'primary.main',
                        color: 'white',
                        display: 'flex',
                        alignItems: 'center',
                        justifyContent: 'center',
                        mx: 'auto',
                        mb: 2,
                        fontWeight: 800,
                        fontSize: '1.5rem',
                      }}
                    >
                      {step.step}
                    </Box>
                    <Typography variant="h5" sx={{ fontWeight: 700, mb: 1 }}>
                      {step.title}
                    </Typography>
                    <Typography variant="body2" color="text.secondary">
                      {step.description}
                    </Typography>
                  </Card>
                </motion.div>
              </Grid>
            ))}
          </Grid>
        </Box>
      </Container>
    </Box>
  );
};

export default Services;

